using Ledgerly.Application.Abstractions; using Ledgerly.Application.Journals; using Ledgerly.Domain.Common; using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.Exceptions; using Ledgerly.Domain.ValueObjects;
namespace Ledgerly.Application.Invoices;
public sealed class InvoiceService { private readonly IInvoiceRepository _invoiceRepository; private readonly IContactRepository _contactRepository; private readonly IAccountRepository _accountRepository; private readonly ITaxCodeRepository _taxCodeRepository; private readonly JournalService _journalService; public InvoiceService(IInvoiceRepository invoiceRepository,IContactRepository contactRepository,IAccountRepository accountRepository,ITaxCodeRepository taxCodeRepository,JournalService journalService){_invoiceRepository=invoiceRepository;_contactRepository=contactRepository;_accountRepository=accountRepository;_taxCodeRepository=taxCodeRepository;_journalService=journalService;} public async Task<Result<InvoiceDto>> CreateAsync(CreateInvoiceRequest request,CancellationToken cancellationToken=default){try{var contact=await _contactRepository.GetByIdAsync(request.OrganizationId,request.CustomerId,cancellationToken);if(contact is null||contact.ContactType!=ContactType.Customer)return Result<InvoiceDto>.Failure("Customer not found.");var currency=new CurrencyCode(request.Currency);var invoice=new Invoice(request.OrganizationId,request.CustomerId,request.InvoiceNumber,request.IssueDate,request.DueDate,currency,request.IncomeAccountId,request.ReceivableAccountId);await _invoiceRepository.AddAsync(invoice,cancellationToken);return Result<InvoiceDto>.Success(await MapAsync(invoice,cancellationToken));}catch(DomainException e){return Result<InvoiceDto>.Failure(e.Message);}} public async Task<Result<InvoiceDto>> GetByIdAsync(Guid organizationId,Guid invoiceId,CancellationToken cancellationToken=default){var invoice=await _invoiceRepository.GetByIdAsync(organizationId,invoiceId,cancellationToken);return invoice is null?Result<InvoiceDto>.Failure("Invoice not found."):Result<InvoiceDto>.Success(await MapAsync(invoice,cancellationToken));} public async Task<Result<InvoiceDto>> AddLineAsync(Guid organizationId,Guid invoiceId,AddInvoiceLineRequest request,CancellationToken cancellationToken=default){try{var invoice=await _invoiceRepository.GetByIdAsync(organizationId,invoiceId,cancellationToken);if(invoice is null)return Result<InvoiceDto>.Failure("Invoice not found.");invoice.AddLine(request.Description,request.Quantity,new Money(request.UnitPriceAmount,invoice.Currency),request.TaxCodeId,new Money(request.DiscountAmount,invoice.Currency));await _invoiceRepository.UpdateAsync(invoice,cancellationToken);return Result<InvoiceDto>.Success(await MapAsync(invoice,cancellationToken));}catch(DomainException e){return Result<InvoiceDto>.Failure(e.Message);}} public async Task<Result<InvoiceDto>> SendAsync(Guid organizationId,Guid invoiceId,CancellationToken cancellationToken=default){try{var invoice=await _invoiceRepository.GetByIdAsync(organizationId,invoiceId,cancellationToken);if(invoice is null)return Result<InvoiceDto>.Failure("Invoice not found.");var taxCodes=await TaxCodesAsync(invoice,cancellationToken);invoice.Send(taxCodes);var journal=await PostAsync(invoice,taxCodes,cancellationToken);if(journal.IsFailure)return Result<InvoiceDto>.Failure(journal.Error!);invoice.AttachJournalEntry(journal.Value!.Id);await _invoiceRepository.UpdateAsync(invoice,cancellationToken);return Result<InvoiceDto>.Success(await MapAsync(invoice,cancellationToken));}catch(DomainException e){return Result<InvoiceDto>.Failure(e.Message);}} public async Task<Result<InvoiceDto>> RecordPaymentAsync(Guid organizationId,Guid invoiceId,RecordPaymentRequest request,CancellationToken cancellationToken=default){try{var invoice=await _invoiceRepository.GetByIdAsync(organizationId,invoiceId,cancellationToken);if(invoice is null)return Result<InvoiceDto>.Failure("Invoice not found.");invoice.RecordPayment(new Money(request.Amount,invoice.Currency));await _invoiceRepository.UpdateAsync(invoice,cancellationToken);return Result<InvoiceDto>.Success(await MapAsync(invoice,cancellationToken));}catch(DomainException e){return Result<InvoiceDto>.Failure(e.Message);}} public async Task<Result<InvoiceDto>> VoidAsync(Guid organizationId,Guid invoiceId,CancellationToken cancellationToken=default){try{var invoice=await _invoiceRepository.GetByIdAsync(organizationId,invoiceId,cancellationToken);if(invoice is null)return Result<InvoiceDto>.Failure("Invoice not found.");if(invoice.JournalEntryId.HasValue){var rev=await _journalService.ReverseAsync(organizationId,invoice.JournalEntryId.Value,cancellationToken);if(rev.IsFailure)return Result<InvoiceDto>.Failure(rev.Error!);}invoice.Void();await _invoiceRepository.UpdateAsync(invoice,cancellationToken);return Result<InvoiceDto>.Success(await MapAsync(invoice,cancellationToken));}catch(DomainException e){return Result<InvoiceDto>.Failure(e.Message);}} private async Task<Result<JournalEntryDto>> PostAsync(Invoice invoice,Dictionary<Guid,TaxCode> taxCodes,CancellationToken ct){var draft=await _journalService.CreateDraftAsync(new CreateJournalRequest(invoice.OrganizationId,invoice.IssueDate,invoice.InvoiceNumber,$"Invoice {invoice.InvoiceNumber}",invoice.Currency.Value),ct);if(draft.IsFailure)return Result<JournalEntryDto>.Failure(draft.Error!);var id=draft.Value!.Id;await _journalService.AddLineAsync(invoice.OrganizationId,id,new AddJournalLineRequest(invoice.ReceivableAccountId,invoice.TotalAmount.Amount,0m,null),ct);await _journalService.AddLineAsync(invoice.OrganizationId,id,new AddJournalLineRequest(invoice.IncomeAccountId,0m,invoice.Subtotal.Amount,null),ct);foreach(var g in invoice.Lines.Where(l=>l.TaxCodeId.HasValue).GroupBy(l=>l.TaxCodeId!.Value)){if(!taxCodes.TryGetValue(g.Key,out var tc))return Result<JournalEntryDto>.Failure("Tax code not found.");var amt=g.Aggregate(new Money(0m,invoice.Currency),(s,l)=>s+l.GetTaxAmount(tc));if(amt.Amount>0)await _journalService.AddLineAsync(invoice.OrganizationId,id,new AddJournalLineRequest(tc.LiabilityAccountId,0m,amt.Amount,null),ct);}return await _journalService.PostAsync(invoice.OrganizationId,id,ct);} private async Task<Dictionary<Guid,TaxCode>> TaxCodesAsync(Invoice invoice,CancellationToken ct){var d=new Dictionary<Guid,TaxCode>();foreach(var id in invoice.Lines.Where(l=>l.TaxCodeId.HasValue).Select(l=>l.TaxCodeId!.Value).Distinct()){var t=await _taxCodeRepository.GetByIdAsync(invoice.OrganizationId,id,ct);if(t is not null)d[id]=t;}return d;} private async Task<InvoiceDto> MapAsync(Invoice invoice,CancellationToken ct){var taxCodes=await TaxCodesAsync(invoice,ct);var lines=invoice.Lines.Select(l=>{var tc=l.TaxCodeId.HasValue&&taxCodes.TryGetValue(l.TaxCodeId.Value,out var t)?t:null;return new InvoiceLineDto(l.Id,l.Description,l.Quantity,l.UnitPrice.Amount,l.TaxCodeId,l.Discount.Amount,l.GetNetAmount().Amount,l.GetTaxAmount(tc).Amount);}).ToList();return new InvoiceDto(invoice.Id,invoice.OrganizationId,invoice.CustomerId,invoice.InvoiceNumber,invoice.IssueDate,invoice.DueDate,invoice.Currency.Value,invoice.IncomeAccountId,invoice.ReceivableAccountId,invoice.Status,invoice.Subtotal.Amount,invoice.TaxTotal.Amount,invoice.TotalAmount.Amount,invoice.AmountPaid.Amount,(invoice.TotalAmount-invoice.AmountPaid).Amount,invoice.JournalEntryId,lines,invoice.CreatedAt,invoice.UpdatedAt);} }
